#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    int N;
    cin >> N;
    int a[10][10];
    int num = 1;
    for (int i = N - 1; i >= 0; i--) {
        for (int j = 0; j < N; j++) {
            a[i][j] = num++;
        }
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            cout << setw(3) << a[i][j];
        }
        cout << '\n';
    }
    return 0;
}
